      "content": "def classify_auth_failure(status_code: int) -> str:\n    # 401 means the service did not accept your identity proof.\n    if status_code == 401:\n        return \"AuthN problem: missing, expired, wrong-audience, or malformed token\"\n    # 403 means identity proof was accepted but permission was missing.\n    if status_code == 403:\n        return \"AuthZ problem: role assignment, scope, or data-plane permission missing\"\n    return \"Not a primary authentication or authorization failure\"\n\nfor code in [401, 403, 404]:\n    print(code, classify_auth_failure(code))\n"
