      "content": "import base64\nimport json\nimport os\nfrom datetime import datetime, timezone\nfrom azure.identity import DefaultAzureCredential\n\nscope = os.getenv(\"AZURE_TOKEN_SCOPE\", \"https://cognitiveservices.azure.com/.default\")\ncredential = DefaultAzureCredential(exclude_environment_credential=True)\ntoken = credential.get_token(scope)\n\npayload = token.token.split(\".\")[1]\npayload += \"=\" * (-len(payload) % 4)\nclaims = json.loads(base64.urlsafe_b64decode(payload))\n\nprint(\"requested_scope\", scope)\nprint(\"audience\", claims.get(\"aud\"))\nprint(\"tenant\", claims.get(\"tid\"))\nprint(\"expires_utc\", datetime.fromtimestamp(token.expires_on, timezone.utc).isoformat())\n"
