      "caption": "Representative prompt to tool call mapping",
      "content": "prompts = {\n    'list my active bugs': {\n        'tool': 'wit_work_item',\n        'action': 'query or my',\n        'risk': 'read',\n        'args': {'workItemType': 'Bug', 'stateNot': 'Closed'},\n    },\n    'create a task': {\n        'tool': 'wit_work_item_write',\n        'action': 'create',\n        'risk': 'write approval required',\n        'args': {'type': 'Task', 'title': '<from user>'},\n    },\n    'show recent pipeline runs': {\n        'tool': 'pipelines_run',\n        'action': 'list',\n        'risk': 'read',\n        'args': {'project': '<project>', 'pipelineId': '<optional>'},\n    },\n    'open a PR': {\n        'tool': 'repo_pull_request_write',\n        'action': 'create',\n        'risk': 'write approval required',\n        'args': {'repository': '<repo>', 'sourceRefName': '<branch>', 'targetRefName': 'main'},\n    },\n}\nfor text, plan in prompts.items():\n    print(text, '=>', plan['tool'], plan['action'], plan['risk'])\n"
